import{_ as a,o as n,c as t,ag as s}from"./chunks/framework.Lq6hU67C.js";const m=JSON.parse('{"title":"IL patterns and limitations","description":"","frontmatter":{},"headers":[],"relativePath":"reference/il-limitations.md","filePath":"reference/il-limitations.md"}'),i={name:"reference/il-limitations.md"};function l(o,e,r,d,c,p){return n(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="il-patterns-and-limitations" tabindex="-1">IL patterns and limitations <a class="header-anchor" href="#il-patterns-and-limitations" aria-label="Permalink to &quot;IL patterns and limitations&quot;">​</a></h1><p>Understanding ILPP constraints helps explain missing entries or edge-case behavior.</p><h2 id="handle-struct-semantics" tabindex="-1">Handle struct semantics <a class="header-anchor" href="#handle-struct-semantics" aria-label="Permalink to &quot;Handle struct semantics&quot;">​</a></h2><p><code>AsyncOperationHandle</code> is a <strong>struct</strong>. The injector tracks:</p><ul><li>The <strong>creation</strong> call site (load)</li><li>The <strong>release</strong> call site</li></ul><p>It does <strong>not</strong> track handle copies passed between methods unless each path has its own load/release call sites.</p><h2 id="load-injection-pattern" tabindex="-1">Load injection pattern <a class="header-anchor" href="#load-injection-pattern" aria-label="Permalink to &quot;Load injection pattern&quot;">​</a></h2><p>Correct pattern after Addressables load:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>call Addressables.LoadAssetAsync</span></span>
<span class="line"><span>stloc handleLocal</span></span>
<span class="line"><span>ldloc handleLocal</span></span>
<span class="line"><span>call HandleTracker.RecordLoad</span></span></code></pre></div><p><strong>Never</strong> <code>Dup</code> immediately after the Addressables <code>call</code> — the struct on stack may not match the stored local used for lifecycle subscription.</p><h2 id="release-injection-pattern" tabindex="-1">Release injection pattern <a class="header-anchor" href="#release-injection-pattern" aria-label="Permalink to &quot;Release injection pattern&quot;">​</a></h2><p>For releases with default optional arguments (e.g. <code>UnloadSceneAsync(handle, autoReleaseHandle: true)</code>):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ldarg handle</span></span>
<span class="line"><span>dup</span></span>
<span class="line"><span>call HandleTracker.RecordRelease</span></span>
<span class="line"><span>ldc.i4_1          ; default bool arg</span></span>
<span class="line"><span>call UnloadSceneAsync</span></span></code></pre></div><p>Injection inserts <strong>after</strong> the handle is loaded and <strong>before</strong> trailing constant arguments.</p><h2 id="generic-handles" tabindex="-1">Generic handles <a class="header-anchor" href="#generic-handles" aria-label="Permalink to &quot;Generic handles&quot;">​</a></h2><p>ILPP calls non-generic <code>HandleTracker</code> methods after <code>AsyncOperationHandle&lt;T&gt;.op_Implicit</code> when needed. Closed generic types (e.g. <code>SceneInstance</code>) use generic <code>RecordLoad&lt;T&gt;</code> / <code>RecordRelease&lt;T&gt;</code> when available.</p><p>Open generic methods in user code may skip injection if handle type cannot be resolved.</p><h2 id="expression-bodied-members" tabindex="-1">Expression-bodied members <a class="header-anchor" href="#expression-bodied-members" aria-label="Permalink to &quot;Expression-bodied members&quot;">​</a></h2><p>Arrow methods returning Addressables calls are supported (same IL as block bodies after compiler lowering).</p><h2 id="assetreference-release" tabindex="-1">AssetReference release <a class="header-anchor" href="#assetreference-release" aria-label="Permalink to &quot;AssetReference release&quot;">​</a></h2><p><code>ReleaseAsset</code> / <code>UnLoadScene</code> inject via the <code>OperationHandle</code> property getter — not the void release method&#39;s implicit handle parameter.</p><h2 id="known-non-instrumented-paths" tabindex="-1">Known non-instrumented paths <a class="header-anchor" href="#known-non-instrumented-paths" aria-label="Permalink to &quot;Known non-instrumented paths&quot;">​</a></h2><p>See <a href="./supported-call-sites.html">Supported call sites</a>.</p><h2 id="engine-internal-retention" tabindex="-1">Engine-internal retention <a class="header-anchor" href="#engine-internal-retention" aria-label="Permalink to &quot;Engine-internal retention&quot;">​</a></h2><p>If Memory Profiler shows retained Addressables content but Live Leaks is empty, Unity may hold references internally — not a missing user <code>Release</code> at an instrumented call site.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./../concepts/handle-identity.html">Handle identity</a></li><li><a href="./../concepts/layers-and-event-log.html">Layers and event log</a></li></ul>`,27)])])}const u=a(i,[["render",l]]);export{m as __pageData,u as default};
